import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    full_path = os.path.join(dir_path, filename)
    abs_dir = os.path.abspath(dir_path)
    abs_file = os.path.abspath(full_path)
    if not abs_file.startswith(abs_dir):
        return ""
    try:
        with open(full_path, 'r') as f:
            return f.read()
    except:
        return ""

def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    if info_type not in {'lang', 'encoding', 'cache'}:
        return header
    new_header = header.copy()
    if info_type == 'lang':
        new_header['Accept-Language'] = info_content
    elif info_type == 'encoding':
        new_header['Accept-Encoding'] = info_content
    else:
        new_header['Cache-Control'] = info_content
    return new_header

