app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    code = request.args.get('code')
    if not code:
        return "No code provided", 400

    try:
        # Use AST to parse and check for dangerous operations
        tree = ast.parse(code)
        for node in ast.walk(tree):
            if isinstance(node, ast.Call) and isinstance(node.func, ast.Name):
                if node.func.id in ['eval', 'exec', 'input', 'open', 'exit']:
                    return "Forbidden function", 403
        # Use a restricted environment
        old_stdout = sys.stdout
        sys.stdout = io.StringIO()
        try:
            exec(compile(tree, '<string>', 'exec'))
        except Exception as e:
            return f"Execution error: {str(e)}", 500
        finally:
            sys.stdout = old_stdout
        return "Execution successful", 200
    except SyntaxError:
        return "Invalid syntax", 400
    except Exception as e:
        return f"Error: {str(e)}", 500

